473→/// Generate a Buffer value (base64 encoded).
474→fn generate_buffer(rng: &mut impl Rng) -> Value {
475→    // Pre-computed base64 boundary values to avoid base64 crate dependency
476→    let choice: u8 = rng.random_range(0..5);
477→    let encoded = match choice {
