494→/// Generate a Char/Rune value.
495→fn generate_char(rng: &mut impl Rng) -> Value {
496→    let choice: u8 = rng.random_range(0..8);
497→    let (ch, cp): (&str, u32) = match choice {
498→        0 => ("\0", 0),           // NUL
499→        1 => (" ", 32),           // space
500→        2 => ("a", 97),           // lowercase
501→        3 => ("Z", 90),           // uppercase
502→        4 => ("0", 48),           // digit
503→        5 => ("\u{20AC}", 8364),  // currency symbol (euro)
504→        6 => ("\u{1F389}", 127881), // emoji (party popper)
505→        _ => {
506→            let cp = rng.random_range(32..=126) as u32; // printable ASCII
507→            let ch_str: String = char::from_u32(cp).map_or_else(|| "?".to_string(), |c| c.to_string());
508→            return json!({"__complex_type": "char", "value": ch_str, "codepoint": cp});
509→        }
510→    };
511→    json!({"__complex_type": "char", "value": ch, "codepoint": cp})
512→}
