735→// ---------------------------------------------------------------------------
736→// Float-biased input generation
737→// ---------------------------------------------------------------------------
738→
739→/// Generate a float value biased toward integers.
740→///
741→/// With probability `integer_ratio`, generates an integer (as f64).
742→/// Otherwise delegates to the standard `generate_float()` distribution.
743→pub fn generate_biased_float(rng: &mut impl Rng, integer_ratio: f64) -> Value {
744→    if rng.random_bool(integer_ratio.clamp(0.0, 1.0)) {
745→        // Generate as integer
746→        let n = rng.random_range(-1000..=1000) as f64;
747→        json!(n)
748→    } else {
749→        generate_float(rng)
750→    }
751→}
752→
753→/// Like [`generate_random_inputs`] but applies integer bias to Float params
754→/// classified as `IntegerTreating`.
755→pub fn generate_random_inputs_with_float_bias(
756→    params: &[crate::types::ParamInfo],
757→    float_bias: &std::collections::HashMap<usize, crate::float_probe::FloatClassification>,
758→    rng: &mut impl Rng,
759→    caps: Option<&FrontendCapabilities>,
760→) -> Vec<Value> {
761→    params
762→        .iter()
763→        .enumerate()
764→        .map(|(i, p)| {
765→            if matches!(p.typ, TypeInfo::Str) {
766→                let hint = heuristic_string_for_name(&p.name)
767→                    .or_else(|| p.type_name.as_deref().and_then(heuristic_string_for_name));
768→                if let Some(val) = hint {
769→                    return json!(val);
770→                }
771→            }
772→            if matches!(p.typ, TypeInfo::Float)
773→                && float_bias.get(&i)
774→                    == Some(&crate::float_probe::FloatClassification::IntegerTreating)
775→            {
776→                return generate_biased_float(rng, crate::float_probe::INTEGER_BIAS_RATIO);
777→            }
778→            generate_random_value(&p.typ, rng, caps)
779→        })
780→        .collect()
781→}
