 998→/// Generate inputs using custom generators where available, falling back to built-in.
 999→///
1000→/// For each parameter, if its `ValueSource` is `CustomGenerator` and the prefetch
1001→/// store has a value available, that value is used. Otherwise, falls back to
1002→/// `generate_random_value`.
1003→pub fn generate_inputs_with_custom(
1004→    params: &[crate::types::ParamInfo],
1005→    sources: &[ValueSource],
1006→    prefetched: &mut PrefetchedValues,
1007→    rng: &mut impl Rng,
1008→    caps: Option<&FrontendCapabilities>,
1009→) -> Vec<Value> {
1010→    params
1011→        .iter()
1012→        .zip(sources.iter())
1013→        .map(|(param, source)| {
1014→            // Check param-name heuristic for Str params before falling back.
1015→            let heuristic = if matches!(param.typ, TypeInfo::Str) {
1016→                heuristic_string_for_name(&param.name)
1017→                    .or_else(|| param.type_name.as_deref().and_then(heuristic_string_for_name))
1018→            } else {
1019→                None
1020→            };
1021→            match source {
1022→                ValueSource::CustomGenerator {
1023→                    generator_name,
1024→                    generator_file,
1025→                    ..
1026→                } => {
1027→                    let file_str = generator_file.display().to_string();
1028→                    prefetched
1029→                        .take(&file_str, generator_name)
1030→                        .unwrap_or_else(|| {
1031→                            heuristic.map_or_else(
1032→                                || generate_random_value(&param.typ, rng, caps),
1033→                                |v| json!(v),
1034→                            )
1035→                        })
1036→                }
1037→                ValueSource::BuiltIn => heuristic.map_or_else(
1038→                    || generate_random_value(&param.typ, rng, caps),
1039→                    |v| json!(v),
1040→                ),
1041→            }
1042→        })
1043→        .collect()
1044→}
